-- WP-011 synthetic jurisdiction seed. Applied by `pnpm local:seed` after
-- module migrations (tables come from
-- modules/platform-core/migrations/0002-jurisdiction.sql). Idempotent
-- upserts; synthetic data only.
--
-- The section between the jurisdiction markers is emitted by
-- renderJurisdictionSeedSection(jurisdictionPacksV1) in
-- @practicehub/platform-core; a drift test compares this file against a
-- fresh emission, and the DB suite compares the seeded rows back against
-- the TypeScript registry.
-- jurisdiction:generated:begin
-- Generated by @practicehub/platform-core renderJurisdictionSeedSection
-- from jurisdictionPacksV1. Regenerate on any pack change; the drift test
-- and the DB registry-sync test fail on divergence.
ON CONFLICT (jurisdiction, version) DO UPDATE
SET effective_on = EXCLUDED.effective_on,
    status = EXCLUDED.status,
    counsel_signoff_ref = EXCLUDED.counsel_signoff_ref,
    change_control_ref = EXCLUDED.change_control_ref,
    synthetic = EXCLUDED.synthetic;

ON CONFLICT (jurisdiction, pack_version, topic) DO UPDATE
SET obligations = EXCLUDED.obligations,
    scalars = EXCLUDED.scalars,
    source_ref = EXCLUDED.source_ref,
    synthetic = EXCLUDED.synthetic;
-- jurisdiction:generated:end

